import React, { useState, useEffect } from 'react';

interface TimerProps {
  duration: number;
  onExpire: () => void;
  active: boolean;
}

export const Timer: React.FC<TimerProps> = ({ duration, onExpire, active }) => {
  const [timeLeft, setTimeLeft] = useState(duration);

  useEffect(() => {
    if (!active) {
      setTimeLeft(duration);
      return;
    }

    if (timeLeft <= 0) {
      onExpire();
      return;
    }

    const timer = setTimeout(() => {
      setTimeLeft(timeLeft - 1);
    }, 1000);

    return () => clearTimeout(timer);
  }, [timeLeft, active, onExpire, duration]);

  if (!active) return null;

  const getColor = () => {
    if (timeLeft > 3) return '#fff';
    if (timeLeft > 1) return '#ff9800';
    return '#f44336';
  };

  return (
    <div style={{
      position: 'fixed',
      bottom: 20,
      right: 20,
      width: 60,
      height: 60,
      borderRadius: '50%',
      background: 'rgba(0,0,0,0.7)',
      border: `2px solid ${getColor()}`,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: 24,
      fontWeight: 'bold',
      color: getColor(),
      zIndex: 100
    }}>
      {timeLeft}
    </div>
  );
};