import React from 'react';

interface SoundControlProps {
  onToggle: (isMuted: boolean) => void;
  isMuted: boolean;
}

export const SoundControl: React.FC<SoundControlProps> = ({ onToggle, isMuted }) => {
  return (
    <button
      onClick={() => onToggle(!isMuted)}
      style={{
        position: 'fixed',
        bottom: 20,
        left: 20,
        zIndex: 200,
        background: 'rgba(0,0,0,0.7)',
        borderRadius: '50%',
        width: 44,
        height: 44,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        cursor: 'pointer',
        border: '1px solid #555',
        backdropFilter: 'blur(4px)',
        fontSize: '20px',
      }}
      aria-label={isMuted ? 'Включить звук' : 'Выключить звук'}
    >
      {isMuted ? '🔇' : '🔊'}
    </button>
  );
};