export interface GameSave {
  userId: number;
  completedActs: number[];
  currentAct: number;
  currentScene?: string;
  sanity: number;
  endingsUnlocked: string[];
  lastPlayed: number;
  puzzleProgress: Record<string, boolean>;
}

const SAVE_KEY = 'silence_horror_save';

export const createEmptySave = (userId: number): GameSave => ({
  userId,
  completedActs: [],
  currentAct: 0,
  sanity: 70,
  endingsUnlocked: [],
  lastPlayed: Date.now(),
  puzzleProgress: {},
});

export const saveGame = (save: GameSave): void => {
  try {
    localStorage.setItem(SAVE_KEY, JSON.stringify({
      ...save,
      lastPlayed: Date.now(),
    }));
    console.log('💾 Игра сохранена:', save);
  } catch (error) {
    console.error('❌ Ошибка сохранения:', error);
  }
};

export const loadGame = (userId: number): GameSave | null => {
  try {
    const raw = localStorage.getItem(SAVE_KEY);
    if (!raw) return null;
    
    const save = JSON.parse(raw) as GameSave;
    
    if (save.userId !== userId) return null;
    
    console.log('📀 Загружено сохранение:', save);
    return save;
  } catch (error) {
    console.error('❌ Ошибка загрузки:', error);
    return null;
  }
};

export const completeAct = (save: GameSave, actNumber: number): GameSave => {
  if (!save.completedActs.includes(actNumber)) {
    save.completedActs.push(actNumber);
    save.completedActs.sort((a, b) => a - b);
  }
  save.currentAct = actNumber + 1;
  save.lastPlayed = Date.now();
  saveGame(save);
  return save;
};

export const completePuzzle = (save: GameSave, puzzleId: string): GameSave => {
  save.puzzleProgress[puzzleId] = true;
  saveGame(save);
  return save;
};

export const addEnding = (save: GameSave, endingId: string): GameSave => {
  if (!save.endingsUnlocked.includes(endingId)) {
    save.endingsUnlocked.push(endingId);
    saveGame(save);
  }
  return save;
};

export const getUnlockedActs = (save: GameSave | null): number[] => {
  if (!save) return [0];
  
  const unlocked = [0];
  
  for (let i = 1; i <= 7; i++) {
    if (save.completedActs.includes(i - 1)) {
      unlocked.push(i);
    }
  }
  
  return unlocked;
};

export const getNextLockedAct = (save: GameSave | null): number | null => {
  const unlocked = getUnlockedActs(save);
  for (let i = 1; i <= 7; i++) {
    if (!unlocked.includes(i)) {
      return i;
    }
  }
  return null;
};