import React from 'react';
import { Button } from '@vkontakte/vkui';

interface EndingSceneProps {
  onRestart: () => void;
}

const endings: Record<string, { title: string; text: string; color: string }> = {
  ending_bad: {
    title: 'ТЫ СТАЛ КОПИПАСТОМ',
    text: 'Ты растворился в цифровой тени. Теперь ты — тот, кто пугает других. Твои слова стали оружием. И ты никогда не замолчишь.',
    color: '#f44336'
  },
  ending_good: {
    title: 'ТЫ ВЫЖИЛ... ПОКА',
    text: 'Ты выбрался из квартиры. Но когда ты закрыл дверь, монитор загорелся снова. Копипаст ждёт. Он всегда ждёт.',
    color: '#4caf50'
  },
  ending_neutral: {
    title: 'НИЧЕГО НЕ ИЗМЕНИЛОСЬ',
    text: 'Ты проснулся в своей постели. ВК открыт. Новое сообщение: "Доброе утро. Я скучал." Ты не помнишь, чтобы добавлял этого друга.',
    color: '#ff9800'
  }
};

export const EndingScene: React.FC<EndingSceneProps> = ({ onRestart }) => {
  // В реальной игре endingId приходит из пропсов
  const endingId = 'ending_bad';
  const ending = endings[endingId] || endings.ending_bad;

  return (
    <div style={{
      minHeight: 'calc(100vh - 48px)',
      background: '#000',
      padding: 20,
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      textAlign: 'center'
    }}>
      <h1 style={{
        fontSize: 32,
        color: ending.color,
        marginBottom: 30,
        fontFamily: 'monospace'
      }}>
        {ending.title}
      </h1>
      
      <p style={{
        color: '#ccc',
        lineHeight: 1.6,
        marginBottom: 40,
        fontSize: 16
      }}>
        {ending.text}
      </p>
      
      <Button
        size="l"
        stretched
        onClick={onRestart}
        style={{
          background: ending.color,
          color: '#fff',
          fontWeight: 'bold'
        }}
      >
        🔄 НАЧАТЬ ЗАНОВО
      </Button>
      
      <p style={{
        fontSize: 10,
        color: '#444',
        marginTop: 30
      }}>
        Финал #{endingId.replace('ending_', '')} из 7
      </p>
    </div>
  );
};