// src/components/scenes/LoadingScene.tsx
import React, { useEffect, useState } from 'react';
import { Spinner } from '@vkontakte/vkui';

export const LoadingScene: React.FC = () => {
  const [debugInfo, setDebugInfo] = useState('Инициализация...');

  useEffect(() => {
    setDebugInfo('1. Компонент загружен');
    
    const checkVK = async () => {
      setDebugInfo('2. Проверка окружения...');
      const isVK = /VK/.test(navigator.userAgent);
      const urlHasVK = window.location.href.includes('vk.com');
      setDebugInfo(`3. isVKWebView: ${isVK}, urlHasVK: ${urlHasVK}`);
      
      if (isVK || urlHasVK) {
        setDebugInfo('');
      } else {
        setDebugInfo('');
      }
    };
    
    checkVK();
  }, []);

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      background: '#000',
      color: '#fff'
    }}>
      <Spinner size="l" />
      <p style={{ marginTop: 80, fontFamily: 'monospace' }}>ЗАГРУЗКА...</p>
      <p style={{ marginTop: 20, fontSize: 12, color: '#ff3366', maxWidth: '80%', textAlign: 'center' }}>
        {debugInfo}
      </p>
    </div>
  );
};