interface PuzzleSceneProps {
  puzzleId: string;
  userId?: number;
  userName?: string;
  onComplete: (nextScene: string) => void;
  onFail: () => void;
  isMuted?: boolean;
  onToggleMute?: () => void;
  backgroundImage?: string | null;
}

// Функция для шифрования имени (сдвиг на 1 букву вперёд)
const encryptName = (name: string): string => {
  const alphabet = 'абвгдеёжзийклмнопрстуфхцчшщъыьэюя';
  return name.toLowerCase().split('').map(char => {
    const index = alphabet.indexOf(char);
    if (index === -1) return char;
    const newIndex = (index + 1) % alphabet.length;
    return alphabet[newIndex];
  }).join('').toUpperCase();
};

// Функция для получения динамической версии головоломки
const getDynamicPuzzle = (basePuzzle: BasePuzzle, userName: string): BasePuzzle => {
  if (basePuzzle.id === 'puzzle_caesar') {
    const encrypted = encryptName(userName);
    const decrypted = userName.toUpperCase();
    
    return {
      ...basePuzzle,
      description: `Копипаст показывает зашифрованное сообщение: «${encrypted}». Оно зашифровано сдвигом на 1 букву назад (А=Б, Б=В...). Какое исходное слово? Это имя, которое тебе дорого.`,
      options: [decrypted, 'Ошибка', 'Неизвестно', 'Другой вариант'],
      correctAnswer: 0,
    };
  }
  return basePuzzle;
};

export const PuzzleScene: React.FC<PuzzleSceneProps> = ({
  puzzleId,
  userId,
  userName = 'БИНА',
  onComplete,
  onFail,
  isMuted = false,
  onToggleMute,
  backgroundImage
}) => {
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [attemptsLeft, setAttemptsLeft] = useState(2);
  const [showHint, setShowHint] = useState(false);
  const [error, setError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);
  const [showScreamer, setShowScreamer] = useState(false);
  const [hintUsed, setHintUsed] = useState(false);
  
  const { play, loadSound } = useSound();
  
  const realPuzzleId = PUZZLE_ID_MAPPING[puzzleId] || puzzleId;
  const basePuzzle = PUZZLES_DB[realPuzzleId];
  
  // Динамическая головоломка (с именем пользователя)
  const puzzle = basePuzzle ? getDynamicPuzzle(basePuzzle, userName) : null;
  
  useEffect(() => {
    loadSound('screamer', '/sounds/skir.mp3');
  }, [loadSound]);
  
  useEffect(() => {
    if (!puzzle) {
      console.error(`❌ Головоломка не найдена: ${puzzleId} -> ${realPuzzleId}`);
      setTimeout(() => onFail(), 1000);
    }
  }, [puzzle, puzzleId, realPuzzleId, onFail]);
  
  if (!puzzle) {
    return (
      <div style={{
        minHeight: '100vh',
        background: '#000',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: '#ff3366'
      }}>
        Ошибка загрузки головоломки...
      </div>
    );
  }
  
  const formatText = (text: string) => {
    if (!userId) return text;
    const accountAgeYears = Math.floor(Math.random() * 5) + 1;
    return text.replace(/{{ACCOUNT_AGE_YEARS}}/g, String(accountAgeYears));
  };
  
  const handleSubmit = () => {
    if (isSuccess) return;
    
    if (selectedOption === null) {
      setError(true);
      setErrorMessage('Выберите вариант ответа!');
      setTimeout(() => setError(false), 1500);
      return;
    }
    
    const isCorrect = selectedOption === puzzle.correctAnswer;
    
    if (isCorrect) {
      setIsSuccess(true);
      if (!isMuted) play('hit', false);
      setTimeout(() => {
        console.log('✅ Отправляем onComplete с:', puzzle.onSuccess);
        onComplete(puzzle.onSuccess);
      }, 1500);
    } else {
      const newAttempts = attemptsLeft - 1;
      setAttemptsLeft(newAttempts);
      setError(true);
      setErrorMessage(`Неверно! Осталось попыток: ${newAttempts}`);
      
      if (!isMuted) play('hit', false);
      setSelectedOption(null);
      
      setTimeout(() => setError(false), 1500);
      
      if (newAttempts <= 0) {
        console.log('💀 ЗАПУСКАЕМ СКРИМЕР!');
        if (!isMuted) play('screamer', false);
        setShowScreamer(true);
      }
    }
  };
  
  const handleUseHint = () => {
    if (hintUsed) return;
    setShowHint(true);
    setHintUsed(true);
  };
  
  const handleEscape = () => {
    window.location.reload();
  };
  
  if (showScreamer) {
    return (
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        zIndex: 9999,
        background: '#000',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        animation: 'screamerFlash 0.1s 3',
      }}>
        <img 
          src="/images/horror/Horror_(15423421559).jpg"
          alt="SCREAMER"
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            opacity: 1,
          }}
          onError={(e) => {
            console.error('❌ Изображение скримера не загрузилось');
            e.currentTarget.style.display = 'none';
          }}
        />
        <Button
          onClick={handleEscape}
          style={{
            position: 'relative',
            zIndex: 10000,
            background: '#8b0000',
            color: '#fff',
            fontWeight: 'bold',
            fontSize: '28px',
            padding: '16px 40px',
            borderRadius: 50,
            border: '2px solid #ff0000',
            boxShadow: '0 0 30px rgba(255,0,0,0.8)',
            textTransform: 'uppercase',
            letterSpacing: 4,
            cursor: 'pointer',
            animation: 'pulseButton 0.5s infinite',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = '#ff0000';
            e.currentTarget.style.transform = 'scale(1.05)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = '#8b0000';
            e.currentTarget.style.transform = 'scale(1)';
          }}
        >
          БЕГИ!!!
        </Button>
      </div>
    );
  }
  
  return (
    <div style={{
        minHeight: '100vh',
        backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none',
        backgroundColor: '#000',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundAttachment: 'fixed',
        backgroundRepeat: 'no-repeat',
        position: 'relative',
    }}>
        <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'rgba(0,0,0,0.7)', // Оставляем затемнение для читаемости текста
        zIndex: 1,
        }} />
      
      <div style={{ position: 'relative', zIndex: 2, padding: 20, minHeight: '100vh' }}>
        <SanityBar sanity={70} />
        
        <div style={{
          background: 'rgba(10,10,10,0.95)',
          borderLeft: '3px solid #ff3366',
          padding: 24,
          borderRadius: 12,
          marginTop: 60
        }}>
          <h2 style={{ 
            color: '#ff3366', 
            marginBottom: 16, 
            fontSize: 20,
            fontFamily: 'monospace'
          }}>
            {puzzle.title}
          </h2>
          
          <p style={{ 
            color: '#ccc', 
            lineHeight: 1.6, 
            marginBottom: 20, 
            whiteSpace: 'pre-line',
            fontSize: 15
          }}>
            {formatText(puzzle.description)}
          </p>
          
          {showHint && (
            <div style={{
              background: 'rgba(255,51,102,0.15)',
              padding: 12,
              borderRadius: 8,
              marginBottom: 20,
              color: '#ff8888',
              fontSize: 13,
              borderLeft: '2px solid #ff3366'
            }}>
              💡 ПОДСКАЗКА: {puzzle.hint}
            </div>
          )}
          
          <div style={{
            marginBottom: 16,
            fontSize: 12,
            color: attemptsLeft === 1 ? '#ff4444' : '#888',
            textAlign: 'right'
          }}>
             Осталось попыток: {attemptsLeft}
          </div>
          
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 20 }}>
            {puzzle.options.map((option, index) => (
              <div
                key={index}
                onClick={() => !isSuccess && setSelectedOption(index)}
                style={{
                  padding: '14px 16px',
                  background: selectedOption === index 
                    ? 'rgba(255,51,102,0.3)' 
                    : 'rgba(20,20,30,0.6)',
                  border: `1px solid ${selectedOption === index ? '#ff3366' : '#444'}`,
                  borderRadius: 10,
                  cursor: isSuccess ? 'default' : 'pointer',
                  transition: 'all 0.2s ease',
                }}
              >
                <span style={{ color: '#fff', fontSize: 15 }}>
                  {String.fromCharCode(65 + index)}. {option}
                </span>
              </div>
            ))}
          </div>
          
          <div style={{ display: 'flex', gap: 12 }}>
            <Button
              onClick={handleUseHint}
              disabled={hintUsed}
              style={{ 
                background: '#333', 
                flex: 1,
                opacity: hintUsed ? 0.5 : 1
              }}
            >
               ПОДСКАЗКА {hintUsed ? '(ИСПОЛЬЗОВАНА)' : ''}
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={isSuccess}
              style={{ 
                background: '#ff3366', 
                flex: 1,
                opacity: isSuccess ? 0.5 : 1
              }}
            >
              {isSuccess ? '✓ ПРАВИЛЬНО!' : 'ОТВЕТИТЬ'}
            </Button>
          </div>
          
          {isSuccess && (
            <div style={{
              marginTop: 16,
              padding: 12,
              background: 'rgba(68,255,68,0.1)',
              borderRadius: 8,
              color: '#88ff88',
              textAlign: 'center',
              border: '1px solid #44ff44'
            }}>
              ✓ Правильно!
            </div>
          )}
        </div>
        
        {error && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(255,0,0,0.3)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
            pointerEvents: 'none',
            animation: 'fadeOut 0.5s ease-in-out'
          }}>
            <div style={{
              background: '#000',
              padding: 20,
              borderRadius: 12,
              border: '2px solid #ff0000',
              color: '#ff0000',
              fontSize: 24,
              fontWeight: 'bold'
            }}>
              {errorMessage}
            </div>
          </div>
        )}
        
        <SoundControl onToggle={onToggleMute || (() => {})} isMuted={isMuted} />
      </div>
      
      <style>{`
        @keyframes fadeOut {
          0% { opacity: 1; }
          70% { opacity: 1; }
          100% { opacity: 0; visibility: hidden; }
        }
        
        @keyframes screamerFlash {
          0% { background: #000; }
          50% { background: #fff; }
          100% { background: #000; }
        }
        
        @keyframes pulseButton {
          0% { transform: scale(1); box-shadow: 0 0 20px rgba(255,0,0,0.5); }
          50% { transform: scale(1.05); box-shadow: 0 0 40px rgba(255,0,0,0.8); }
          100% { transform: scale(1); box-shadow: 0 0 20px rgba(255,0,0,0.5); }
        }
      `}</style>
    </div>
  );
};