import React, { useState, useEffect } from 'react';
import { AdaptivityProvider, AppRoot, View, Panel, PanelHeader, Button, Input } from '@vkontakte/vkui';
import '@vkontakte/vkui/dist/vkui.css';
import './styles/global.css';

import { useVKUser } from './hooks/useVKUser';
import { LoadingScene } from './components/scenes/LoadingScene';
import { StartScene } from './components/scenes/StartScene';
import { DialogScene } from './components/scenes/DialogScene';
import { EndingScene } from './components/scenes/EndingScene';
import { PuzzleScene } from './components/Puzzle/PuzzleScene';
import { ActSelectionScene } from './components/scenes/ActSelectionScene';
import { ImagePreloader } from './components/UI/ImagePreloader';
import { GameSave, loadGame, saveGame, createEmptySave, addEnding } from './utils/saveSystem';

type GameState = 'loading' | 'preload' | 'ageGate' | 'consent' | 'start' | 'actSelection' | 'dialog' | 'puzzle' | 'ending';

const STORAGE_KEY = 'silence_horror_current_scene';
const CONSENT_KEY = 'silence_horror_consent_given';
const AGE_VERIFIED_KEY = 'silence_horror_age_verified';
type PuzzleCallback = (success: boolean, nextScene?: string) => void;

const ALL_IMAGES: string[] = [
  '/images/backgrounds/prologue/bg_phone_message.jpeg',
  '/images/backgrounds/prologue/bg_blured_photo.jpeg',
  '/images/backgrounds/prologue/bg_incoming_call.jpeg',
  '/images/backgrounds/prologue/bg_call_history.jpeg',
  '/images/backgrounds/prologue/bg_night_street.jpeg',
  '/images/backgrounds/prologue/bg_abandoned_house.jpeg',
  '/images/backgrounds/scene1/bg_dark_staircase.jpeg',
  '/images/backgrounds/scene1/bg_ajar_door.jpg',
  '/images/backgrounds/scene1/bg_empty_room.jpeg',
  '/images/backgrounds/scene1/bg_monitor_vk.jpeg',
  '/images/backgrounds/scene1/bg_chat_black_square.jpeg',
  '/images/backgrounds/scene1/bg_reflection.jpeg',
  '/images/backgrounds/final/bg_dawn_room.jpeg',
  '/images/backgrounds/final/bg_to_be_continued.jpeg',
  '/images/horror/Horror_(15423421559).jpg',
];

function App() {
  const [gameState, setGameState] = useState<GameState>('loading');
  const [endingId, setEndingId] = useState<string>('');
  const [currentPuzzleId, setCurrentPuzzleId] = useState<string>('');
  const [currentBackground, setCurrentBackground] = useState<string | null>(null);
  const [pendingNextScene, setPendingNextScene] = useState<string | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved && saved !== 'prologue_memory' ? saved : null;
  });
  const [isMuted, setIsMuted] = useState(false);
  const [puzzleCallback, setPuzzleCallback] = useState<PuzzleCallback | undefined>(undefined);
  const [dialogKey, setDialogKey] = useState<number>(Date.now());
  const [preloadComplete, setPreloadComplete] = useState(false);
  const [gameSave, setGameSave] = useState<GameSave | null>(null);
  const [consentGiven, setConsentGiven] = useState<boolean>(() => {
    return localStorage.getItem(CONSENT_KEY) === 'true';
  });
  const [ageVerified, setAgeVerified] = useState<boolean>(() => {
    return localStorage.getItem(AGE_VERIFIED_KEY) === 'true';
  });
  const [privacyAccepted, setPrivacyAccepted] = useState(false);
  const [birthYear, setBirthYear] = useState<string>('');
  const [ageError, setAgeError] = useState<string>('');
  const { user, loading } = useVKUser();
  const [selectedAct, setSelectedAct] = useState<number>(0);

  useEffect(() => {
    if (user && !loading) {
      const save = loadGame(user.id);
      if (save) {
        setGameSave(save);
        console.log('📀 Загружено сохранение для пользователя:', user.first_name);
      } else {
        const newSave = createEmptySave(user.id);
        setGameSave(newSave);
        saveGame(newSave);
        console.log('📀 Создано новое сохранение для пользователя:', user.first_name);
      }
      setGameState('preload');
    }
  }, [user, loading]);

  const handlePreloadComplete = () => {
    setPreloadComplete(true);
    if (ageVerified) {
      if (consentGiven) {
        setGameState('start');
      } else {
        setGameState('consent');
      }
    } else {
      setGameState('ageGate');
    }
  };

  const handleAgeConfirm = () => {
    const year = parseInt(birthYear);
    const currentYear = new Date().getFullYear();
    const age = currentYear - year;
    
    if (!birthYear || isNaN(year) || year < 1900 || year > currentYear) {
      setAgeError('Введите корректный год рождения');
      return;
    }
    
    if (age >= 16) {
      localStorage.setItem(AGE_VERIFIED_KEY, 'true');
      setAgeVerified(true);
      setAgeError('');
      setGameState('consent');
    } else {
      setAgeError('Извините, игра предназначена для пользователей старше 16 лет');
    }
  };

  const handleAgeReject = () => {
    if (window.history.length > 1) {
      window.history.back();
    } else {
      window.location.href = 'https://vk.com';
    }
  };

  const handleConsentAccept = () => {
    localStorage.setItem(CONSENT_KEY, 'true');
    setConsentGiven(true);
    setGameState('start');
  };

  const handleStart = () => {
    setGameState('actSelection');
  };
  
  const handleSelectAct = (actNumber: number) => {
    setSelectedAct(actNumber);
    setPendingNextScene(null);
    setDialogKey(Date.now());
    setGameState('dialog');
  };
  
  const handleEnding = (id: string) => {
    setEndingId(id);
    if (gameSave) {
      addEnding(gameSave, id);
    }
    setGameState('ending');
  };
  
  const handleRestart = () => {
    setGameState('actSelection');
  };
  
  const handleResetProgress = () => {
    if (user && confirm('Точно сбросить весь прогресс? Копипаст не забудет...')) {
      const newSave = createEmptySave(user.id);
      setGameSave(newSave);
      saveGame(newSave);
      setGameState('start');
    }
  };
  
  const handlePuzzle = (puzzleId: string, callback: PuzzleCallback, currentBg?: string) => {
    console.log('🧩 Открываем головоломку:', puzzleId);
    setCurrentPuzzleId(puzzleId);
    setCurrentBackground(currentBg || null);
    setPuzzleCallback(() => callback);
    setGameState('puzzle');
  };
  
  const handlePuzzleComplete = (nextScene: string) => {
    console.log('🔓 Головоломка решена, переходим к сцене:', nextScene);
    
    if (puzzleCallback) {
      puzzleCallback(true, nextScene);
      setPuzzleCallback(undefined);
    }
    
    setPendingNextScene(nextScene);
    setDialogKey(Date.now());
    setGameState('dialog');
  };
  
  const handlePuzzleFail = () => {
    console.log('💀 Головоломка провалена');
    
    if (puzzleCallback) {
      puzzleCallback(false);
      setPuzzleCallback(undefined);
    }
    
    setDialogKey(Date.now());
    setGameState('actSelection');
  };
  
  const handleToggleMute = () => {
    setIsMuted(!isMuted);
  };

  const handleActComplete = (completedActNumber: number) => {
    console.log(`🎉 Акт ${completedActNumber} завершён! Обновляем сохранение`);
    if (gameSave) {
      const updatedSave = { ...gameSave };
      if (!updatedSave.completedActs.includes(completedActNumber)) {
        updatedSave.completedActs.push(completedActNumber);
        updatedSave.completedActs.sort((a, b) => a - b);
        updatedSave.currentAct = completedActNumber + 1;
        setGameSave(updatedSave);
        saveGame(updatedSave);
        console.log('💾 Сохранение обновлено:', updatedSave);
      }
    }
  };

  if (gameState === 'loading' || loading) {
    return (
      <AdaptivityProvider>
        <AppRoot>
          <View activePanel="main">
            <Panel id="main">
              <LoadingScene />
            </Panel>
          </View>
        </AppRoot>
      </AdaptivityProvider>
    );
  }

  if (gameState === 'preload') {
    return <ImagePreloader images={ALL_IMAGES} onComplete={handlePreloadComplete} />;
  }

  // ВОЗРАСТНОЙ ГЕЙТ (16+)
  if (gameState === 'ageGate') {
    return (
      <AdaptivityProvider>
        <AppRoot>
          <View activePanel="ageGate">
            <Panel id="ageGate">
              <PanelHeader style={{ background: '#000', color: '#fff', borderBottom: '1px solid #333' }}>
                ТИШИНА
              </PanelHeader>
              <div style={{
                minHeight: 'calc(100vh - 48px)',
                background: '#000',
                padding: 20,
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
              }}>
                <div style={{
                  background: 'rgba(10,10,10,0.95)',
                  borderLeft: '3px solid #ff3366',
                  padding: 24,
                  borderRadius: 12,
                }}>
                  <h2 style={{ color: '#ff3366', marginBottom: 16, fontSize: 20 }}>
                    🔞 ВОЗРАСТНОЕ ОГРАНИЧЕНИЕ
                  </h2>
                  
                  <p style={{ color: '#ffffff', marginBottom: 16, lineHeight: 1.5 }}>
                    Игра «Тишина» содержит элементы психологического хоррора,<br/>
                    пугающие звуковые эффекты и визуальные образы,<br/>
                    которые могут быть неподходящими для лиц младше 16 лет.
                  </p>
                  
                  <div style={{
                    background: 'rgba(255,51,102,0.1)',
                    padding: 12,
                    borderRadius: 8,
                    marginBottom: 20,
                    border: '1px solid rgba(255,51,102,0.3)',
                  }}>
                    <p style={{ color: '#ff8888', fontSize: 14, margin: 0 }}>
                      ⚠️ Рекомендуемый возраст: <strong style={{ color: '#ff3366' }}>16+</strong>
                    </p>
                  </div>
                  
                  <div style={{ marginBottom: 20 }}>
                    <p style={{ color: '#ffffff', marginBottom: 8, fontSize: 14 }}>
                      Ваш год рождения:
                    </p>
                    <Input
                      type="number"
                      placeholder="Например: 2005"
                      value={birthYear}
                      onChange={(e) => setBirthYear(e.target.value)}
                      style={{
                        background: '#1a1a1a',
                        border: ageError ? '1px solid #ff4444' : '1px solid #333',
                        color: '#ffffff',
                        marginBottom: 8,
                      }}
                    />
                    {ageError && (
                      <p style={{ color: '#ff4444', fontSize: 12, marginTop: 4 }}>
                        {ageError}
                      </p>
                    )}
                  </div>
                  
                  <div style={{ display: 'flex', gap: 12 }}>
                    <Button
                      stretched
                      onClick={handleAgeConfirm}
                      style={{ 
                        background: '#ff3366',
                        flex: 1,
                        color: '#ffffff',
                        fontWeight: 'bold',
                      }}
                    >
                      ✅ МНЕ ЕСТЬ 16 ЛЕТ
                    </Button>
                    <Button
                      stretched
                      onClick={handleAgeReject}
                      style={{ 
                        background: '#333',
                        flex: 1,
                        color: '#ffffff',
                      }}
                    >
                      ❌ МНЕ НЕТ 16
                    </Button>
                  </div>
                </div>
              </div>
            </Panel>
          </View>
        </AppRoot>
      </AdaptivityProvider>
    );
  }

  // ЭКРАН СОГЛАСИЯ (ONBOARDING) — ИСПРАВЛЕННЫЙ
  // ЭКРАН СОГЛАСИЯ (ONBOARDING) — ИСПРАВЛЕННЫЙ
  if (gameState === 'consent') {
    return (
      <AdaptivityProvider>
        <AppRoot>
          <View activePanel="consent">
            <Panel id="consent">
              <PanelHeader style={{ background: '#000', color: '#fff', borderBottom: '1px solid #333' }}>
                ТИШИНА
              </PanelHeader>
              <div style={{
                minHeight: 'calc(100vh - 48px)',
                background: '#000',
                padding: 20,
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
              }}>
                <div style={{
                  background: 'rgba(10,10,10,0.95)',
                  borderLeft: '3px solid #ff3366',
                  padding: 24,
                  borderRadius: 12,
                }}>
                  <h2 style={{ color: '#ff3366', marginBottom: 16, fontSize: 20 }}>
                    ⚠️ КОПИПАСТ ПРОСИТ ДОСТУП
                  </h2>
                  
                  <p style={{ color: '#ffffff', marginBottom: 16, lineHeight: 1.5 }}>
                    Игра «Тишина» использует <strong style={{ color: '#ff3366' }}>только открытые данные вашего профиля</strong> для персонализации страха:
                  </p>
                  
                  <ul style={{ color: '#cccccc', marginBottom: 24, paddingLeft: 20, lineHeight: 1.6 }}>
                    <li>👤 Имя и фамилия</li>
                    <li>🖼 Аватар</li>
                    <li>👥 Количество друзей (только цифра)</li>
                    <li>📸 Количество фотографий (только цифра)</li>
                    <li>👁 Количество подписчиков (только цифра)</li>
                    <li>📅 Возраст аккаунта</li>
                  </ul>
                  
                  <div style={{
                    background: 'rgba(255,51,102,0.1)',
                    padding: 12,
                    borderRadius: 8,
                    marginBottom: 20,
                    border: '1px solid rgba(255,51,102,0.3)',
                  }}>
                    <p style={{ color: '#ff8888', fontSize: 14, margin: 0 }}>
                      ❌ <strong>Мы НЕ собираем:</strong> личные сообщения, пароли, номера телефонов, закрытые альбомы, данные карт.
                    </p>
                  </div>
                  
                  {/* КАСТОМНЫЙ ЧЕКБОКС + РАБОЧИЕ ССЫЛКИ */}
                  <div style={{ marginBottom: 24 }}>
                    <div 
                      onClick={() => {
                        console.log('🖱️ Чекбокс нажат, предыдущее значение:', privacyAccepted);
                        setPrivacyAccepted(!privacyAccepted);
                      }}
                      style={{ 
                        display: 'flex', 
                        alignItems: 'flex-start', 
                        gap: 12, 
                        cursor: 'pointer',
                      }}
                    >
                      <div style={{
                        width: 20,
                        height: 20,
                        border: `1px solid ${privacyAccepted ? '#ff3366' : '#555'}`,
                        background: privacyAccepted ? '#ff3366' : 'transparent',
                        borderRadius: 4,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        marginTop: 2,
                        flexShrink: 0
                      }}>
                        {privacyAccepted && <span style={{ color: '#fff', fontSize: 14 }}>✓</span>}
                      </div>
                      <div style={{ color: '#ccc', fontSize: 14, lineHeight: 1.4 }}>
                        Я принимаю{' '}
                        <span 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            console.log('🔗 Открываем политику конфиденциальности');
                            window.open('https://budnikcam.github.io/legal/privacy.html', '_blank');
                          }}
                          style={{ color: '#ff6699', cursor: 'pointer', textDecoration: 'underline' }}
                        >
                          политику конфиденциальности
                        </span>{' '}
                        и{' '}
                        <span 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            console.log('🔗 Открываем пользовательское соглашение');
                            window.open('https://budnikcam.github.io/legal/terms.html', '_blank');
                          }}
                          style={{ color: '#ff6699', cursor: 'pointer', textDecoration: 'underline' }}
                        >
                          пользовательское соглашение
                        </span>
                      </div>
                    </div>
                  </div>
                  
                  <Button
                    stretched
                    disabled={!privacyAccepted}
                    onClick={() => {
                      console.log('🎮 Кнопка "Я СОГЛАСЕН" нажата, согласие:', privacyAccepted);
                      handleConsentAccept();
                    }}
                    style={{ 
                      background: privacyAccepted ? '#ff3366' : '#333',
                      opacity: privacyAccepted ? 1 : 0.5,
                      cursor: privacyAccepted ? 'pointer' : 'not-allowed',
                      color: '#ffffff',
                      fontWeight: 'bold',
                    }}
                  >
                    🎮 Я СОГЛАСЕН, КОПИПАСТ МОЖЕТ НАЧАТЬ
                  </Button>
                  
                  <p style={{
                    fontSize: 11,
                    color: '#888888',
                    textAlign: 'center',
                    marginTop: 20,
                  }}>
                    Вы можете отозвать согласие в любой момент, очистив данные приложения в настройках VK
                  </p>
                </div>
              </div>
            </Panel>
          </View>
        </AppRoot>
      </AdaptivityProvider>
    );
  }

  return (
    <AdaptivityProvider>
      <AppRoot>
        <View activePanel="main">
          <Panel id="main">
            <PanelHeader style={{ background: '#000', color: '#fff', borderBottom: '1px solid #333' }}>
              ТИШИНА
            </PanelHeader>
            
            {gameState === 'start' && (
              <StartScene user={user} onStart={handleStart} />
            )}
            
            {gameState === 'actSelection' && (
              <ActSelectionScene 
                save={gameSave} 
                onSelectAct={handleSelectAct}
                onReset={handleResetProgress}
                userName={user?.first_name}
              />
            )}
            
            {gameState === 'dialog' && (
              <DialogScene 
                key={dialogKey}
                user={user} 
                onEnding={handleEnding}
                onRestart={handleRestart}
                onPuzzle={handlePuzzle}
                initialScene={pendingNextScene}
                onSceneConsumed={() => setPendingNextScene(null)}
                actNumber={selectedAct}
                onActComplete={handleActComplete}
              />
            )}
            
            {gameState === 'puzzle' && (
              <PuzzleScene
                puzzleId={currentPuzzleId}
                userId={user?.id}
                userName={user?.first_name}
                onComplete={handlePuzzleComplete}
                onFail={handlePuzzleFail}
                isMuted={isMuted}
                onToggleMute={handleToggleMute}
                backgroundImage={currentBackground}
              />
            )}
            
            {gameState === 'ending' && (
              <EndingScene onRestart={handleRestart} />
            )}
          </Panel>
        </View>
      </AppRoot>
    </AdaptivityProvider>
  );
}

export default App;