import { useState, useEffect } from 'react';
import bridge from '@vkontakte/vk-bridge';

const API_PROXY = import.meta.env.VITE_VK_API_PROXY || 'https://functions.yandexcloud.net/d4ep5tp4f5i7no5sraua';

export interface VKUser {
  id: number;
  first_name: string;
  last_name: string;
  photo_100: string;
  photo_200?: string;
  sex: number;
  city?: string;
  country?: string;
  bdate?: string;
  friends_count: number;
  followers_count: number;
  photos_count: number;
  groups_count: number;
  account_age_days: number;
  is_private: boolean;
}

const HORROR_PHRASES = [
  'Твой профиль закрыт. Но Копипаст всё равно видит тебя.',
  'Закрытый профиль? Копипаст знает, что ты скрываешь.',
  'Ты думаешь, приватность спасёт? Копипаст уже внутри.',
  'Даже закрытый профиль не защитит от Копипаста.',
];

export const useVKUser = () => {
  const [user, setUser] = useState<VKUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [horrorMessage, setHorrorMessage] = useState<string>('');

  useEffect(() => {
    const initVK = async () => {
      try {
        console.log('1️⃣ useVKUser: начали загрузку');
        
        await bridge.send('VKWebAppInit', {});
        console.log('2️⃣ VKWebAppInit успешно');
        
        const userData = await bridge.send('VKWebAppGetUserInfo', {});
        console.log('3️⃣ Пользователь из VK Bridge:', userData);
        
        // Проверяем, что данные получены корректно
        const firstName = userData.first_name || 'Игрок';
        const lastName = userData.last_name || '';
        const userId = userData.id || 0;
        
        let friendsCount = 0;
        let followersCount = 0;
        let photosCount = 0;
        let accountAgeDays = 365;
        let city = '';
        let country = '';
        let photo100 = '';
        let photo200 = '';
        let sex = 0;
        let bdate = '';
        let isPrivate = false;
        
        try {
          const url = `${API_PROXY}?user_id=${userId}`;
          console.log('5️⃣ Запрос к функции:', url);
          const response = await fetch(url);
          const data = await response.json();
          
          console.log('6️⃣ Ответ от Cloud Function:', data);
          
          if (data && data.id) {
            friendsCount = data.friends_count || 0;
            followersCount = data.followers_count || 0;
            photosCount = data.photos_count || 0;
            accountAgeDays = data.account_age_days || 365;
            city = data.city || '';
            country = data.country || '';
            photo100 = data.photo_100;
            photo200 = data.photo_200;
            sex = data.sex || 0;
            bdate = data.bdate || '';
            isPrivate = false;
            console.log(`✅ Данные получены: друзей=${friendsCount}, фото=${photosCount}, подписчиков=${followersCount}`);
          } else {
            console.log('⚠️ Данные не получены, профиль возможно закрыт');
            isPrivate = true;
            setHorrorMessage(HORROR_PHRASES[Math.floor(Math.random() * HORROR_PHRASES.length)]);
          }
        } catch (e) {
          console.log('❌ Ошибка запроса к Cloud Function:', e);
          isPrivate = true;
          setHorrorMessage('Копипаст не может получить данные. Но он всё равно здесь.');
        }
        
        setUser({
          id: userId,
          first_name: firstName,
          last_name: lastName,
          photo_100: photo100 || userData.photo_100 || 'https://vk.com/images/camera_100.png',
          photo_200: photo200 || userData.photo_200,
          sex: sex || userData.sex || 0,
          city: city || userData.city?.title || '',
          country: country || '',
          bdate: bdate || userData.bdate || '',
          friends_count: friendsCount,
          followers_count: followersCount,
          photos_count: photosCount,
          groups_count: 0,
          account_age_days: accountAgeDays,
          is_private: isPrivate,
        });
        
        setLoading(false);
        
      } catch (err) {
        console.error('❌ Ошибка инициализации VK:', err);
        // Fallback для разработки/ошибок
        setUser({
          id: Date.now(),
          first_name: 'Игрок',
          last_name: '',
          photo_100: 'https://vk.com/images/camera_100.png',
          sex: 0,
          city: '',
          country: '',
          bdate: '',
          friends_count: 0,
          followers_count: 0,
          photos_count: 0,
          groups_count: 0,
          account_age_days: 365,
          is_private: false,
        });
        setHorrorMessage('');
        setError('Режим офлайн');
        setLoading(false);
      }
    };

    initVK();
  }, []);

  return { user, loading, error, horrorMessage };
};