import React, { useState } from 'react';
import { Button } from '@vkontakte/vkui';
import { GameSave, getUnlockedActs, getNextLockedAct } from '../../utils/saveSystem';

interface Act {
  number: number;
  title: string;
  description: string;
  isLocked: boolean;
  isHidden?: boolean;
  isComingSoon?: boolean; // ДЛЯ АКТОВ, КОТОРЫЕ В РАЗРАБОТКЕ
}

const ALL_ACTS: Act[] = [
  { number: 0, title: 'ПРОЛОГ', description: 'Знакомство с Копипастом', isLocked: false, isHidden: false, isComingSoon: false },
  { number: 1, title: 'АКТ 1: ЦИФРОВАЯ ТЕНЬ', description: 'Копипаст раскрывает свою природу', isLocked: true, isHidden: false, isComingSoon: true },
  { number: 2, title: 'АКТ 2: УДАЛЁННЫЕ ФАЙЛЫ', description: 'Путешествие по удалённым воспоминаниям', isLocked: true, isHidden: true, isComingSoon: false },
  { number: 3, title: 'АКТ 3: ДРУЗЬЯ И ВРАГИ', description: 'Тайна фейковых профилей', isLocked: true, isHidden: true, isComingSoon: false },
  { number: 4, title: 'АКТ 4: СОХРАНЁННОЕ', description: 'Изменённые сохранёнки', isLocked: true, isHidden: true, isComingSoon: false },
  { number: 5, title: 'АКТ 5: ЧАТ С ПРОШЛЫМ', description: 'Встреча с собой из прошлого', isLocked: true, isHidden: true, isComingSoon: false },
  { number: 6, title: 'АКТ 6: СЛИЯНИЕ', description: 'Финальная битва с Копипастом', isLocked: true, isHidden: true, isComingSoon: false },
  { number: 7, title: 'АКТ 7: ПЕРЕЗАГРУЗКА', description: 'Выбор концовки', isLocked: true, isHidden: true, isComingSoon: false },
];

// СООБЩЕНИЯ ДЛЯ АКТОВ В РАЗРАБОТКЕ
const COMING_SOON_MESSAGES = [
  '🎭 Этот акт ещё в разработке. Скоро Копипаст расскажет новую главу...',
  '📝 Сценарий этого акта пишется прямо сейчас. Загляни позже!',
  '🎬 Копипаст набирается сил для следующего акта. Ожидайте обновления!',
  '⚙️ Тьма сгущается... Акт в разработке. Скоро вы узнаете продолжение!',
  '📖 История продолжается... Этот акт появится в следующем обновлении.',
  '👁 Копипаст готовит для тебя кое-что особенное. Акт скоро выйдет!',
];

interface ActSelectionSceneProps {
  save: GameSave | null;
  onSelectAct: (actNumber: number) => void;
  onReset: () => void;
  userName?: string;
}

export const ActSelectionScene: React.FC<ActSelectionSceneProps> = ({ 
  save, 
  onSelectAct, 
  onReset,
  userName = 'игрок'
}) => {
  const [showComingSoonMessage, setShowComingSoonMessage] = useState(false);
  const [comingSoonMessage, setComingSoonMessage] = useState('');
  const [messageGlitch, setMessageGlitch] = useState(false);
  
  const unlockedActs = getUnlockedActs(save);
  const nextLockedAct = getNextLockedAct(save);
  
  // ЛОГИКА ОТОБРАЖЕНИЯ АКТОВ:
  // - Пролог всегда виден
  // - Все акты с isComingSoon=true видны, но при нажатии показывают сообщение
  // - Остальные акты скрыты (isHidden=true)
  const visibleActs = ALL_ACTS.filter(act => {
    if (act.number === 0) return true; // Пролог всегда виден
    if (unlockedActs.includes(act.number)) return true; // Разблокированные видны
    if (act.isComingSoon) return true; // Акты "Скоро" видны
    if (act.number === nextLockedAct) return true; // Следующий заблокированный виден
    return false;
  }).map(act => ({
    ...act,
    // Акт ЗАБЛОКИРОВАН, если он НЕ Пролог И НЕ в списке разблокированных И НЕ isComingSoon
    isLocked: act.number !== 0 && !unlockedActs.includes(act.number) && !act.isComingSoon,
  }));

  const completedCount = save?.completedActs.length || 0;
  const totalActsRevealed = visibleActs.length;
  const progressPercent = totalActsRevealed > 0 ? Math.round((completedCount / totalActsRevealed) * 100) : 0;

  const handleActClick = (act: Act) => {
    console.log('🖱️ Нажат акт:', act.number, 'isLocked:', act.isLocked, 'isComingSoon:', act.isComingSoon);
    
    // Если акт в разработке — показываем сообщение
    if (act.isComingSoon) {
      const randomMessage = COMING_SOON_MESSAGES[Math.floor(Math.random() * COMING_SOON_MESSAGES.length)];
      setComingSoonMessage(randomMessage);
      setShowComingSoonMessage(true);
      setMessageGlitch(true);
      setTimeout(() => setMessageGlitch(false), 300);
      setTimeout(() => setShowComingSoonMessage(false), 3000);
      return;
    }
    
    // Если акт доступен
    if (!act.isLocked) {
      onSelectAct(act.number);
      return;
    }
    
    // Если акт заблокирован и это следующий (СКОРО) — показываем сообщение
    if (act.number === nextLockedAct && !act.isComingSoon) {
      const randomMessage = COMING_SOON_MESSAGES[Math.floor(Math.random() * COMING_SOON_MESSAGES.length)];
      setComingSoonMessage(randomMessage);
      setShowComingSoonMessage(true);
      setMessageGlitch(true);
      setTimeout(() => setMessageGlitch(false), 300);
      setTimeout(() => setShowComingSoonMessage(false), 3000);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0a0a0a 0%, #000000 100%)',
      padding: '20px',
      display: 'flex',
      flexDirection: 'column',
      position: 'relative',
    }}>
      {/* Сообщение о будущих актах */}
      {showComingSoonMessage && (
        <div style={{
          position: 'fixed',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          zIndex: 1000,
          background: 'rgba(0,0,0,0.95)',
          border: `2px solid ${messageGlitch ? '#ff3366' : '#333'}`,
          borderRadius: 12,
          padding: '20px 24px',
          maxWidth: '80%',
          textAlign: 'center',
          animation: 'fadeInOut 3s ease-in-out forwards',
          boxShadow: '0 0 30px rgba(255,51,102,0.3)',
        }}>
          <p style={{
            color: '#ff8888',
            fontSize: 14,
            lineHeight: 1.5,
            fontFamily: 'monospace',
            margin: 0,
          }}>
            {comingSoonMessage}
          </p>
        </div>
      )}
      
      <div style={{ textAlign: 'center', marginBottom: 30 }}>
        <h1 style={{
          fontSize: 36,
          letterSpacing: 4,
          color: '#ff3366',
          marginBottom: 16,
          fontFamily: 'monospace',
        }}>
          ВЫБОР АКТА
        </h1>
        
        <div style={{
          width: '80%',
          maxWidth: 300,
          margin: '0 auto',
          marginBottom: 8,
        }}>
          <div style={{
            width: '100%',
            height: 4,
            background: '#1a1a1a',
            borderRadius: 2,
            overflow: 'hidden',
          }}>
            <div style={{
              width: `${progressPercent}%`,
              height: '100%',
              background: '#ff3366',
              transition: 'width 0.3s ease',
            }} />
          </div>
        </div>
        <p style={{ color: '#888', fontSize: 12 }}>
          Пройдено актов: {completedCount} / {totalActsRevealed}
        </p>
      </div>
      
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        gap: 12,
        maxWidth: 400,
        margin: '0 auto',
        width: '100%',
        marginBottom: 30,
      }}>
        {visibleActs.map((act) => (
          <Button
            key={act.number}
            size="l"
            stretched
            onClick={() => handleActClick(act)}
            disabled={act.isLocked && !act.isComingSoon}
            style={{
              background: (act.isComingSoon || act.isLocked) ? 'rgba(30,30,40,0.5)' : 'rgba(20,20,30,0.8)',
              border: `1px solid ${(act.isComingSoon || act.isLocked) ? '#333' : '#ff3366'}`,
              color: (act.isComingSoon || act.isLocked) ? '#666' : '#fff',
              borderRadius: 12,
              padding: '16px 20px',
              height: 'auto',
              minHeight: '90px',
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              textAlign: 'center',
              cursor: (act.isComingSoon || act.isLocked) ? 'pointer' : 'pointer',
              opacity: (act.isComingSoon || act.isLocked) ? 0.7 : 1,
            }}
          >
            <div style={{ width: '100%', textAlign: 'center' }}>
              <div style={{
                fontSize: 12,
                color: (act.isComingSoon || act.isLocked) ? '#ff8866' : '#ff3366',
                marginBottom: 6,
                letterSpacing: 1,
              }}>
                {act.isComingSoon 
                  ? '🎭 СКОРО'
                  : act.isLocked 
                    ? '🔒 ЗАКРЫТ'
                    : '✅ ДОСТУПЕН'}
              </div>
              <div style={{ 
                fontSize: 16, 
                fontWeight: 'bold', 
                marginBottom: 6,
                lineHeight: 1.3,
                color: (act.isComingSoon || act.isLocked) ? '#aaa' : '#fff',
              }}>
                {act.title}
              </div>
              <div style={{ 
                fontSize: 11, 
                color: (act.isComingSoon || act.isLocked) ? '#666' : '#aaa',
                lineHeight: 1.4,
              }}>
                {act.description}
              </div>
            </div>
          </Button>
        ))}
        
        {/* Намёк на будущие акты */}
        {ALL_ACTS.length > visibleActs.length && (
          <div style={{
            textAlign: 'center',
            padding: 20,
            color: '#333',
            fontSize: 12,
            fontStyle: 'italic',
          }}>
            ✦ · ✦ · ✦
            <br />
            Что-то скрыто во тьме...
            <br />
            Продолжай игру, чтобы увидеть больше
          </div>
        )}
      </div>
      
      <div style={{ display: 'flex', gap: 12, justifyContent: 'center' }}>
        <Button
          onClick={onReset}
          style={{
            background: 'transparent',
            border: '1px solid #444',
            color: '#fff',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
        >
          🗑️ СБРОСИТЬ ПРОГРЕСС
        </Button>
      </div>
      
      <p style={{
        textAlign: 'center',
        fontSize: 10,
        color: '#444',
        marginTop: 30,
      }}>
        Пройденные акты открывают новые главы. Тьма постепенно рассеивается...
      </p>
      
      <style>{`
        @keyframes fadeInOut {
          0% { opacity: 0; transform: translate(-50%, -50%) scale(0.9); }
          15% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
          85% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
          100% { opacity: 0; transform: translate(-50%, -50%) scale(0.9); visibility: hidden; }
        }
      `}</style>
    </div>
  );
};