import { useRef, useCallback } from 'react';
import { Howl } from 'howler';

interface SoundMap {
  [key: string]: Howl;
}

const SOUNDS = {
  drone: '/sounds/drone_loop.mp3',
  horror_ambient: '/sounds/horror_ambient.mp3',
  hit: '/sounds/horror_hit.mp3',
  whisper: '/sounds/whisper.mp3',
  to_be_continued: '/sounds/to_be_continued.wav',
  screamer: '/sounds/skir.mp3',
};

export const useSound = () => {
  const sounds = useRef<SoundMap>({});

  // Загрузка одного звука по имени
  const loadSound = useCallback((name: string, src?: string) => {
    const soundSrc = src || SOUNDS[name as keyof typeof SOUNDS];
    if (!soundSrc) {
      console.warn(`No sound source for: ${name}`);
      return;
    }
    
    if (!sounds.current[name]) {
      sounds.current[name] = new Howl({
        src: [soundSrc],
        volume: name === 'drone' ? 0.3 : 0.5,
        loop: name === 'drone' || name === 'horror_ambient',
        preload: true,
        onloaderror: (id, error) => {
          console.warn(`Failed to load sound: ${name}`, error);
        },
      });
    }
  }, []);

  // Загрузка всех звуков
  const loadAllSounds = useCallback(() => {
    Object.entries(SOUNDS).forEach(([name, src]) => {
      loadSound(name, src);
    });
  }, [loadSound]);

  const play = useCallback((name: string, loop = false) => {
    const sound = sounds.current[name];
    if (sound) {
      if (loop) sound.loop(true);
      sound.play();
    } else {
      console.warn(`Sound not loaded: ${name}`);
    }
  }, []);

  const stop = useCallback((name: string) => {
    const sound = sounds.current[name];
    if (sound) {
      sound.stop();
      if (sound.loop()) sound.loop(false);
    }
  }, []);

  const stopAll = useCallback(() => {
    Object.values(sounds.current).forEach((sound) => {
      sound.stop();
      if (sound.loop()) sound.loop(false);
    });
  }, []);

  const setAmbient = useCallback((ambientName: string, loop = true) => {
    // Останавливаем предыдущий ambient
    Object.entries(sounds.current).forEach(([name, sound]) => {
      if (name.startsWith('ambient') || name === 'drone') {
        sound.stop();
        if (sound.loop()) sound.loop(false);
      }
    });
    
    play(ambientName, loop);
  }, [play]);

  const stopAmbient = useCallback(() => {
    Object.entries(sounds.current).forEach(([name, sound]) => {
      if (name.startsWith('ambient') || name === 'drone') {
        sound.stop();
        if (sound.loop()) sound.loop(false);
      }
    });
  }, []);

  const setVolume = useCallback((name: string, volume: number) => {
    const sound = sounds.current[name];
    if (sound) {
      sound.volume(Math.max(0, Math.min(1, volume)));
    }
  }, []);

  return {
    loadSound,
    loadAllSounds,
    play,
    stop,
    stopAll,
    setAmbient,
    stopAmbient,
    setVolume,
    sounds: SOUNDS,
  };
};