import React, { useState, useEffect, useRef } from 'react';
import { Button } from '@vkontakte/vkui';
import { SanityBar } from '../UI/SanityBar';
import { GlitchText } from '../UI/GlitchText';
import { Timer } from '../UI/Timer';
import { SoundControl } from '../UI/SoundControl';
import { VKUser } from '../../hooks/useVKUser';
import { useSound } from '../../hooks/useSound';
import dialogTreeRaw from '../../data/dialogTree.json';

interface DialogChoice {
  text: string;
  nextScene: string;
  sanityChange: number;
}

interface DialogNode {
  id: string;
  text: string;
  choices: DialogChoice[];
}

const dialogTree = dialogTreeRaw as Record<string, DialogNode>;

const sceneConfig: Record<string, { background: string; ambient: string; action?: string }> = {
  prologue_memory: { background: '/images/backgrounds/prologue/bg_phone_message.jpeg', ambient: 'drone', action: '' },
  prologue_photo: { background: '/images/backgrounds/prologue/bg_blured_photo.jpeg', ambient: 'drone', action: '' },
  prologue_call: { background: '/images/backgrounds/prologue/bg_incoming_call.jpeg', ambient: 'drone', action: '' },
  prologue_ignore: { background: '/images/backgrounds/prologue/bg_incoming_call.jpeg', ambient: 'drone', action: '' },
  prologue_search: { background: '/images/backgrounds/prologue/bg_call_history.jpeg', ambient: 'drone', action: '' },
  prologue_road: { background: '/images/backgrounds/prologue/bg_night_street.jpeg', ambient: 'drone', action: '' },
  scene1_enter: { background: '/images/backgrounds/scene1/bg_dark_staircase.jpeg', ambient: 'drone', action: '' },
  scene1_apartment: { background: '/images/backgrounds/scene1/bg_ajar_door.jpg', ambient: 'drone', action: '' },
  after_puzzle_success_1: { background: '/images/backgrounds/prologue/bg_abandoned_house.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_2: { background: '/images/backgrounds/scene1/bg_empty_room.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_3: { background: '/images/backgrounds/scene1/bg_chat_black_square.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_4: { background: '/images/backgrounds/scene1/bg_monitor_vk.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_5: { background: '/images/backgrounds/scene1/bg_reflection.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_6: { background: '/images/backgrounds/scene1/bg_monitor_vk.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_7: { background: '/images/backgrounds/scene1/bg_empty_room.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_8: { background: '/images/backgrounds/scene1/bg_chat_black_square.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_9: { background: '/images/backgrounds/scene1/bg_reflection.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_10: { background: '/images/backgrounds/scene1/bg_monitor_vk.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_11: { background: '/images/backgrounds/scene1/bg_empty_room.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_12: { background: '/images/backgrounds/scene1/bg_dark_staircase.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_13: { background: '/images/backgrounds/scene1/bg_ajar_door.jpg', ambient: 'drone', action: '' },
  after_puzzle_success_14: { background: '/images/backgrounds/scene1/bg_monitor_vk.jpeg', ambient: 'drone', action: '' },
  after_puzzle_success_15: { background: '/images/backgrounds/scene1/bg_empty_room.jpeg', ambient: 'drone', action: '' },
  to_be_continued: { background: '/images/backgrounds/final/bg_dawn_room.jpeg', ambient: '', action: 'to_be_continued' },
  end_of_demo: { background: '/images/backgrounds/final/bg_to_be_continued.jpeg', ambient: '', action: '' },
  puzzle_fail_horror: { background: '/images/backgrounds/horror/bg_horror_fail.jpg', ambient: '', action: 'hit' },
};

interface DialogSceneProps {
  user: VKUser | null;
  onEnding: (endingId: string) => void;
  onRestart?: () => void;
  onPuzzle?: (puzzleId: string, callback: (success: boolean, nextScene?: string) => void, background?: string) => void;
  initialScene?: string | null;
  onSceneConsumed?: () => void;
  actNumber?: number;
  onActComplete?: (actNumber: number) => void;
}

export const DialogScene: React.FC<DialogSceneProps> = ({ 
  user, 
  onEnding, 
  onRestart,
  onPuzzle,
  initialScene,
  onSceneConsumed,
  actNumber,
  onActComplete
}) => {
  const [currentNodeId, setCurrentNodeId] = useState<string>(() => {
    if (initialScene && dialogTree[initialScene]) {
      console.log('🎬 Устанавливаем начальную сцену:', initialScene);
      return initialScene;
    }
    console.log('🎬 Начальная сцена по умолчанию: prologue_memory');
    return 'prologue_memory';
  });
  
  const [sanity, setSanity] = useState(70);
  const [timerActive, setTimerActive] = useState(false);
  const [shake, setShake] = useState(false);
  const [bloodIntensity, setBloodIntensity] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [showHorrorOverlay, setShowHorrorOverlay] = useState(false);
  const { loadAllSounds, play, stopAll, setAmbient, stopAmbient } = useSound();
  const [actCompleted, setActCompleted] = useState(false);
  
  const ACT_END_SCENES: Record<number, string[]> = {
    0: ['to_be_continued', 'end_of_demo'],
    1: ['act1_end'],
    2: ['act2_end'],
    3: ['act3_end'],
    4: ['act4_end'],
    5: ['act5_end'],
    6: ['act6_end'],
    7: ['act7_end'],
  };
  
  const initialAppliedRef = useRef(false);

  useEffect(() => {
    if (!actCompleted && actNumber !== undefined && currentNodeId) {
      const endScenes = ACT_END_SCENES[actNumber] || [];
      if (endScenes.includes(currentNodeId)) {
        console.log(`🎉 Акт ${actNumber} завершён!`);
        setActCompleted(true);
        if (onActComplete) {
          onActComplete(actNumber);
        }
      }
    }
  }, [currentNodeId, actNumber, actCompleted, onActComplete]);

  useEffect(() => {
    if (initialScene && dialogTree[initialScene] && !initialAppliedRef.current) {
      console.log('🔄 Применяем initialScene:', initialScene);
      setCurrentNodeId(initialScene);
      initialAppliedRef.current = true;
      if (onSceneConsumed) onSceneConsumed();
    }
  }, [initialScene, onSceneConsumed]);

  const currentNode = dialogTree[currentNodeId];
  const config = sceneConfig[currentNodeId] || { background: '', ambient: 'drone' };

  useEffect(() => {
    loadAllSounds();
  }, [loadAllSounds]);

  useEffect(() => {
    if (isMuted) return;
    
    if (config.ambient) {
      setAmbient(config.ambient, true);
    } else {
      stopAmbient();
    }
    
    if (config.action) {
      setTimeout(() => play(config.action!, false), 100);
    }
  }, [currentNodeId, config, isMuted, setAmbient, stopAmbient, play]);

  useEffect(() => {
    if (isMuted) return;
    
    if (sanity < 30) {
      setShake(true);
      setBloodIntensity(0.5);
    } else if (sanity < 50) {
      setShake(true);
      setBloodIntensity(0.2);
    } else {
      setShake(false);
      setBloodIntensity(0);
    }
  }, [sanity, isMuted]);

  const handleSoundToggle = (muted: boolean) => {
    setIsMuted(muted);
    if (muted) stopAll();
  };

  const getRandomInRange = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
  const getRandomYear = () => getRandomInRange(2020, 2026);
  const getRandomDaysAgo = () => getRandomInRange(1, 30);
  const getRandomWeeksAgo = () => getRandomInRange(1, 8);
  
  const commentPreviews = ['привет', 'круто', 'ого', 'класс', 'ок', 'вау', 'супер', 'огонь'];

  const formatText = (text: string) => {
    if (!user) return text;
    
    // Получаем расшифрованное имя (имя пользователя в верхнем регистре)
    const decryptedName = user.first_name.toUpperCase();
    
    if (user.is_private) {
      const horrorPlaceholders = ['???', '[скрыто]', 'неизвестно', '● ● ●', 'тайна'];
      const randomPlaceholder = () => horrorPlaceholders[Math.floor(Math.random() * horrorPlaceholders.length)];
      
      return text
        .replace(/{{USER_NAME}}/g, user.first_name)
        .replace(/{{DECRYPTED_NAME}}/g, decryptedName)
        .replace(/{{FULL_NAME}}/g, `${user.first_name} ${user.last_name}`)
        .replace(/{{FRIENDS_COUNT}}/g, randomPlaceholder())
        .replace(/{{PHOTOS_COUNT}}/g, randomPlaceholder())
        .replace(/{{FOLLOWERS_COUNT}}/g, randomPlaceholder())
        .replace(/{{ACCOUNT_AGE_DAYS}}/g, randomPlaceholder())
        .replace(/{{ACCOUNT_AGE_YEARS}}/g, randomPlaceholder())
        .replace(/{{GENDER}}/g, randomPlaceholder())
        .replace(/{{CITY}}/g, randomPlaceholder())
        .replace(/{{BIRTH_YEAR}}/g, randomPlaceholder())
        .replace(/{{CALLS_COUNT}}/g, randomPlaceholder())
        .replace(/{{LAST_POST_DATE}}/g, randomPlaceholder())
        .replace(/{{FRIEND_LAST_POST_DATE}}/g, randomPlaceholder())
        .replace(/{{SAVED_PHOTO_YEAR}}/g, randomPlaceholder())
        .replace(/{{UNREAD_MESSAGES}}/g, randomPlaceholder())
        .replace(/{{DELETED_POSTS_COUNT}}/g, randomPlaceholder())
        .replace(/{{NEW_POSTS_COUNT}}/g, randomPlaceholder())
        .replace(/{{FIRST_COMMENT_PREVIEW}}/g, randomPlaceholder())
        .replace(/{{FIRST_LIKE_YEAR}}/g, randomPlaceholder());
    }
    
    const accountAgeYears = Math.floor((user.account_age_days || 730) / 365);
    const genderText = user.sex === 1 ? 'девушка' : user.sex === 2 ? 'парень' : 'человек';
    
    const callsCount = getRandomInRange(1, 20);
    const lastPostDate = `${getRandomDaysAgo()} дня(ей) назад`;
    const friendLastPostDate = `${getRandomWeeksAgo()} недель(и) назад`;
    const savedPhotoYear = String(getRandomYear());
    const unreadMessages = getRandomInRange(5, 50);
    const deletedPostsCount = getRandomInRange(10, 100);
    const newPostsCount = getRandomInRange(1, 20);
    const firstCommentPreview = `...${commentPreviews[Math.floor(Math.random() * commentPreviews.length)]}...`;
    const firstLikeYear = String(getRandomYear());
    
    return text
      .replace(/{{USER_NAME}}/g, user.first_name)
      .replace(/{{DECRYPTED_NAME}}/g, decryptedName)
      .replace(/{{FULL_NAME}}/g, `${user.first_name} ${user.last_name}`)
      .replace(/{{FRIENDS_COUNT}}/g, String(user.friends_count || 0))
      .replace(/{{PHOTOS_COUNT}}/g, String(user.photos_count || 0))
      .replace(/{{FOLLOWERS_COUNT}}/g, String(user.followers_count || 0))
      .replace(/{{ACCOUNT_AGE_DAYS}}/g, String(user.account_age_days || 730))
      .replace(/{{ACCOUNT_AGE_YEARS}}/g, String(accountAgeYears))
      .replace(/{{GENDER}}/g, genderText)
      .replace(/{{CITY}}/g, user.city || 'неизвестном городе')
      .replace(/{{BIRTH_YEAR}}/g, user.bdate?.split('.')[2] || '????')
      .replace(/{{CALLS_COUNT}}/g, String(callsCount))
      .replace(/{{LAST_POST_DATE}}/g, lastPostDate)
      .replace(/{{FRIEND_LAST_POST_DATE}}/g, friendLastPostDate)
      .replace(/{{SAVED_PHOTO_YEAR}}/g, savedPhotoYear)
      .replace(/{{UNREAD_MESSAGES}}/g, String(unreadMessages))
      .replace(/{{DELETED_POSTS_COUNT}}/g, String(deletedPostsCount))
      .replace(/{{NEW_POSTS_COUNT}}/g, String(newPostsCount))
      .replace(/{{FIRST_COMMENT_PREVIEW}}/g, firstCommentPreview)
      .replace(/{{FIRST_LIKE_YEAR}}/g, firstLikeYear);
  };

  const handleChoice = (choice: DialogChoice) => {
    if (!isMuted) play('hit', false);
    
    const newSanity = Math.max(0, Math.min(100, sanity + choice.sanityChange));
    setSanity(newSanity);
    
    if (choice.nextScene.startsWith('puzzle_')) {
      if (onPuzzle) {
        onPuzzle(choice.nextScene, (success: boolean, nextScene?: string) => {
          if (success && nextScene) {
            console.log(`✅ Головоломка решена, переходим на ${nextScene}`);
          } else {
            setShowHorrorOverlay(true);
            if (!isMuted) play('hit', false);
            setTimeout(() => {
              setShowHorrorOverlay(false);
              setCurrentNodeId('puzzle_fail_horror');
            }, 2000);
          }
        }, config.background);
      }
      return;
    }
    
    if (choice.nextScene === 'act_selection') {
      if (onActComplete && actNumber !== undefined) {
        onActComplete(actNumber);
      }
      if (onRestart) {
        onRestart();
      }
      return;
    }
    
    if (choice.nextScene === 'end_of_demo' && onRestart) {
      stopAmbient();
      // ВЫЗЫВАЕМ onActComplete ПЕРЕД РЕСТАРТОМ
      if (onActComplete && actNumber !== undefined) {
        onActComplete(actNumber);
      }
      setTimeout(() => onRestart(), 2000);
      return;
    }
    
    if (choice.nextScene.startsWith('ending_')) {
      stopAmbient();
      onEnding(choice.nextScene);
      return;
    }
    
    const nextNode = dialogTree[choice.nextScene];
    if (nextNode) {
      if (!isMuted && choice.sanityChange !== 0) play('hit', false);
      setCurrentNodeId(choice.nextScene);
      if (choice.sanityChange < -10) {
        setTimerActive(true);
        setTimeout(() => setTimerActive(false), 5000);
      }
    }
  };

  const onTimerExpire = () => {
    setSanity(Math.max(0, sanity - 15));
    setTimerActive(false);
    if (!isMuted) play('hit', false);
  };

  if (!currentNode) {
    return <div style={{ padding: 20, color: '#fff' }}>Ошибка: сцена не найдена</div>;
  }

  
  return (
    <div style={{
      minHeight: '100vh',
      backgroundImage: config.background ? `url(${config.background})` : 'none',
      backgroundColor: '#0a0a0a',
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      backgroundAttachment: 'fixed',
      backgroundRepeat: 'no-repeat',
      position: 'relative',
    }}>
      {/* УМЕНЬШАЕМ ЗАТЕМНЕНИЕ ДЛЯ ЛУЧШЕЙ ВИДИМОСТИ */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'rgba(0,0,0,0.35)', // Было 0.5, уменьшили
        zIndex: 1,
      }} />
      
      <div style={{ position: 'relative', zIndex: 2, padding: '16px', minHeight: '100vh' }}>
        <SanityBar sanity={sanity} />
        
        <div className={shake ? 'shake' : ''}>
          <div style={{
            background: 'rgba(0,0,0,0.85)',
            borderLeft: `4px solid ${sanity < 30 ? '#ff4444' : '#ff3366'}`,
            padding: '20px 16px',
            marginTop: 60,
            marginBottom: 30,
            borderRadius: 12,
            backdropFilter: 'blur(4px)',
          }}>
            <GlitchText 
              text={formatText(currentNode.text)} 
              glitch={sanity < 30}
            />
          </div>
          
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {currentNode.choices.map((choice, index) => (
              <Button
                key={index}
                size="l"
                stretched
                onClick={() => handleChoice(choice)}
                style={{
                  background: 'transparent',
                  border: 'none',
                  color: '#ffffff',
                  borderRadius: 10,
                  padding: '14px 20px',
                  fontSize: '15px',
                  textAlign: 'center',
                  justifyContent: 'center',
                  height: 'auto',
                  minHeight: '52px',
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  textShadow: '0 0 5px rgba(0,0,0,0.5)',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.color = '#ff3366';
                  e.currentTarget.style.transform = 'scale(1.02)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.color = '#ffffff';
                  e.currentTarget.style.transform = 'scale(1)';
                }}
              >
                {choice.text}
              </Button>
            ))}
          </div>
        </div>
        
        {bloodIntensity > 0 && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            pointerEvents: 'none',
            background: `radial-gradient(circle, transparent 50%, rgba(80,0,0,${bloodIntensity}) 100%)`,
            zIndex: 10,
          }} />
        )}
        
        {showHorrorOverlay && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 1000,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: 'rgba(0,0,0,0.7)',
            animation: 'fadeOut 2s ease-in-out forwards',
            pointerEvents: 'none',
          }}>
            <img 
              src="/images/horror/Horror_(15423421559).jpg"
              alt="horror"
              style={{
                maxWidth: '90%',
                maxHeight: '90%',
                opacity: 0.85,
                borderRadius: 8,
                boxShadow: '0 0 30px rgba(255,0,0,0.5)',
              }}
            />
          </div>
        )}
        
        <Timer duration={5} onExpire={onTimerExpire} active={timerActive} />
        <SoundControl onToggle={handleSoundToggle} isMuted={isMuted} />
      </div>
      
      <style>{`
        @keyframes fadeOut {
          0% { opacity: 1; }
          70% { opacity: 1; }
          100% { opacity: 0; visibility: hidden; display: none; }
        }
      `}</style>
    </div>
  );
};