import React from 'react';

interface SanityBarProps {
  sanity: number;
}

export const SanityBar: React.FC<SanityBarProps> = ({ sanity }) => {
  const getColor = () => {
    if (sanity > 66) return '#4caf50';
    if (sanity > 33) return '#ff9800';
    return '#f44336';
  };

  const getMessage = () => {
    if (sanity > 66) return 'Разум стабилен';
    if (sanity > 33) return 'Тревога нарастает';
    if (sanity > 10) return 'Грань безумия';
    return 'Ты теряешь себя';
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      padding: '10px 20px',
      background: 'rgba(0,0,0,0.8)',
      zIndex: 100,
      borderBottom: '1px solid #333'
    }}>
      <div style={{ marginBottom: 5, fontSize: 12, color: '#aaa' }}>
        {getMessage()}
      </div>
      <div style={{
        width: '100%',
        height: 4,
        background: '#333',
        borderRadius: 2,
        overflow: 'hidden'
      }}>
        <div style={{
          width: `${sanity}%`,
          height: '100%',
          background: getColor(),
          transition: 'width 0.3s ease'
        }} />
      </div>
    </div>
  );
};