import React, { useEffect, useState } from 'react';
import { Button } from '@vkontakte/vkui';
import { VKUser } from '../../hooks/useVKUser';

interface StartSceneProps {
  user: VKUser | null;
  onStart: () => void;
  horrorMessage?: string;
}

// Жуткие сообщения для закрытых профилей
const PRIVATE_PROFILE_PHRASES = [
  ' Твой профиль закрыт. Но я всё равно вижу каждый твой шаг.',
  ' Приватность не спасёт. Я уже внутри твоего телефона.',
  ' Ты скрываешь свои секреты. Но я знаю их все.',
  ' Закрытый профиль? Копипаст уважает тайны... но не твои.',
  ' Ты думаешь, что невидимка. Ошибаешься.',
];

export const StartScene: React.FC<StartSceneProps> = ({ user, onStart, horrorMessage }) => {
  const [displayPhrase, setDisplayPhrase] = useState<string>('');
  const [isPrivate, setIsPrivate] = useState(false);

  useEffect(() => {
    if (user) {
      // Проверка на закрытый профиль: если друзей 0 и фото 0 и подписчиков 0 — скорее всего закрыт
      const likelyPrivate = user.is_private || 
        (user.friends_count === 0 && user.photos_count === 0 && user.followers_count === 0);
      
      if (likelyPrivate || horrorMessage) {
        setIsPrivate(true);
        // Выбираем случайное жуткое сообщение
        const randomPhrase = PRIVATE_PROFILE_PHRASES[Math.floor(Math.random() * PRIVATE_PROFILE_PHRASES.length)];
        setDisplayPhrase(horrorMessage || randomPhrase);
      } else {
        setIsPrivate(false);
        const phrases = [
          `У тебя ${user.friends_count} друзей. Но я слышу только одного — тебя.`,
          `Ты загрузил ${user.photos_count} фото. Я смотрел каждое. Даже те, что ты удалил.`,
          `У тебя ${user.followers_count} подписчиков. Они следят за тобой. Я — тоже.`,
          `Твой аккаунт живёт ${Math.floor(user.account_age_days / 365)} лет. Я был здесь с первого дня.`,
        ];
        setDisplayPhrase(phrases[Math.floor(Math.random() * phrases.length)]);
      }
    }
  }, [user, horrorMessage]);

  if (!user) return null;

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0a0a0a 0%, #000000 100%)',
      padding: '20px',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
    }}>
      <div style={{ textAlign: 'center', marginBottom: 40, width: '100%', maxWidth: 320 }}>
        <h1 style={{
          fontSize: 42,
          letterSpacing: 6,
          color: '#ff3366',
          marginBottom: 24,
          fontFamily: 'monospace',
        }}>
          ТИШИНА
        </h1>
        
        <div style={{ marginBottom: 24 }}>
          <img 
            src={user.photo_100} 
            alt="avatar" 
            style={{
              width: 100,
              height: 100,
              borderRadius: '50%',
              border: '2px solid #ff3366',
              objectFit: 'cover',
            }}
          />
          <p style={{ marginTop: 12, color: '#fff', fontSize: 18, fontWeight: 'bold' }}>
            {user.first_name} {user.last_name}
          </p>
        </div>
        
        {/* Статистика (только если профиль открытый и есть реальные данные) */}
        {!isPrivate && !horrorMessage && (
          <div style={{
            background: 'rgba(255,51,102,0.1)',
            borderRadius: 12,
            padding: '12px 16px',
            marginBottom: 24,
            border: '1px solid rgba(255,51,102,0.3)',
            backdropFilter: 'blur(4px)',
          }}>
            <p style={{ color: '#ff3366', fontSize: 12, marginBottom: 8 }}>
              📊 КОПИПАСТ УЖЕ ВСЁ ЗНАЕТ
            </p>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              <span style={{ color: '#ccc', fontSize: 12 }}>👥 Друзей: {user.friends_count}</span>
              <span style={{ color: '#ccc', fontSize: 12 }}>📸 Фото: {user.photos_count}</span>
              <span style={{ color: '#ccc', fontSize: 12 }}>👁 Подписчиков: {user.followers_count}</span>
              <span style={{ color: '#ccc', fontSize: 12 }}>📅 Лет в ВК: {Math.floor(user.account_age_days / 365)}</span>
            </div>
          </div>
        )}
        
        {/* Хоррор-сообщение */}
        <div style={{
          background: isPrivate || horrorMessage 
            ? 'rgba(255,51,102,0.15)' 
            : 'rgba(0,0,0,0.5)',
          borderRadius: 12,
          padding: '16px',
          marginBottom: 32,
          border: `1px solid ${isPrivate || horrorMessage ? '#ff3366' : '#333'}`,
          backdropFilter: 'blur(4px)',
        }}>
          <p style={{ 
            color: isPrivate || horrorMessage ? '#ff8888' : '#aaa', 
            fontSize: 14, 
            lineHeight: 1.5, 
            margin: 0,
            fontStyle: 'italic',
            textAlign: 'center'
          }}>
            {displayPhrase}
          </p>
        </div>
        
        {/* Дополнительное жуткое предупреждение для закрытых профилей */}
        {isPrivate && (
          <div style={{
            background: 'rgba(0,0,0,0.5)',
            borderRadius: 8,
            padding: '8px 12px',
            marginBottom: 20,
            fontSize: 10,
            color: '#666',
            textAlign: 'center',
          }}>
             Копипаст не может увидеть твои данные... но он чувствует твой страх.
          </div>
        )}
      </div>
      
      <Button
        size="l"
        onClick={onStart}
        style={{
          background: '#ff3366',
          color: '#fff',
          fontWeight: 'bold',
          fontSize: '18px',
          padding: '12px 32px',
          borderRadius: 40,
          width: 'auto',
          minWidth: 200,
          height: 'auto',
          cursor: 'pointer',
          transition: 'all 0.2s ease',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = '#ff5577';
          e.currentTarget.style.transform = 'scale(1.02)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = '#ff3366';
          e.currentTarget.style.transform = 'scale(1)';
        }}
      >
         НАЧАТЬ ИГРУ
      </Button>
      
      <p style={{
        textAlign: 'center',
        fontSize: 10,
        color: '#444',
        marginTop: 48,
        maxWidth: 260,
      }}>
        {isPrivate 
          ? ' Копипаст уважает приватность. Но он всё равно знает, кто ты.'
          : ' Копипаст уже знает всё о тебе. Будь осторожен.'}
      </p>
    </div>
  );
};