// client/src/components/UI/ImagePreloader.tsx
import React, { useEffect, useState } from 'react';

interface ImagePreloaderProps {
  images: string[];
  onComplete: () => void;
}

// ПУГАЮЩИЕ СООБЩЕНИЯ ДЛЯ ЗАГРУЗКИ
const HORROR_MESSAGES = [
  'Копипаст сканирует твои фото...',
  'Анализ старых комментариев...',
  'Поиск удалённых сообщений...',
  'Чтение твоих сохранёнок...',
  'Копипаст изучает твоих друзей...',
  'Восстановление удалённых постов...',
  'Копипаст запоминает твои лайки...',
  'Сбор цифровой тени...',
  'Твои секреты раскрываются...',
  'Копипаст уже внутри...',
  'Осталось немного...',
  'Копипаст ждал тебя...',
  'Твои слова против тебя...',
  'Прошлое возвращается...',
  'Копипаст почти готов...',
];

export const ImagePreloader: React.FC<ImagePreloaderProps> = ({ images, onComplete }) => {
  const [loaded, setLoaded] = useState(0);
  const [total] = useState(images.length);
  const [currentMessageIndex, setCurrentMessageIndex] = useState(0);
  const [glitch, setGlitch] = useState(false);

  // Меняем сообщение каждые 1.5 секунды
  useEffect(() => {
    if (total === 0) return;
    
    const interval = setInterval(() => {
      setCurrentMessageIndex((prev) => {
        const next = (prev + 1) % HORROR_MESSAGES.length;
        // Эффект глитча при смене сообщения
        setGlitch(true);
        setTimeout(() => setGlitch(false), 200);
        return next;
      });
    }, 1800);

    return () => clearInterval(interval);
  }, [total]);

  useEffect(() => {
    if (images.length === 0) {
      onComplete();
      return;
    }

    let mounted = true;

    images.forEach((src) => {
      const img = new Image();
      img.onload = () => {
        if (mounted) {
          setLoaded((prev) => {
            const newLoaded = prev + 1;
            if (newLoaded === total) {
              setTimeout(() => onComplete(), 1000);
            }
            return newLoaded;
          });
        }
      };
      img.onerror = () => {
        console.warn(`❌ Не удалось загрузить изображение: ${src}`);
        if (mounted) {
          setLoaded((prev) => {
            const newLoaded = prev + 1;
            if (newLoaded === total) {
              setTimeout(() => onComplete(), 1000);
            }
            return newLoaded;
          });
        }
      };
      img.src = src;
    });

    return () => {
      mounted = false;
    };
  }, [images, total, onComplete]);

  const progress = total > 0 ? Math.round((loaded / total) * 100) : 100;
  const currentMessage = HORROR_MESSAGES[currentMessageIndex];

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: '#000',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 9999,
    }}>
      {/* Эффект статики на фоне */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'repeating-linear-gradient(0deg, rgba(0,0,0,0.8) 0px, rgba(255,255,255,0.03) 2px, rgba(0,0,0,0.8) 4px)',
        pointerEvents: 'none',
        opacity: 0.3,
      }} />
      
      {/* Глаз Копипаста */}
      <div style={{
        width: 60,
        height: 60,
        borderRadius: '50%',
        background: '#1a0a0a',
        border: '2px solid #ff3366',
        marginBottom: 40,
        position: 'relative',
        animation: 'pulseEye 2s ease-in-out infinite',
      }}>
        <div style={{
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          width: 20,
          height: 20,
          borderRadius: '50%',
          background: '#ff3366',
          animation: 'blink 3s infinite',
        }} />
      </div>
      
      {/* Пугающее сообщение с глитчем */}
      <p style={{
        color: '#ff3366',
        fontSize: 16,
        fontFamily: 'monospace',
        letterSpacing: 2,
        marginBottom: 30,
        textAlign: 'center',
        padding: '0 20px',
        textTransform: 'uppercase',
        animation: glitch ? 'textGlitch 0.2s ease-in-out' : 'none',
      }}>
        {currentMessage}
      </p>
      
      {/* Прогресс-бар */}
      <div style={{
        width: '70%',
        maxWidth: 250,
        height: 2,
        background: '#1a1a1a',
        borderRadius: 1,
        overflow: 'hidden',
        marginBottom: 12,
      }}>
        <div style={{
          width: `${progress}%`,
          height: '100%',
          background: '#ff3366',
          transition: 'width 0.3s ease',
        }} />
      </div>
      
      {/* Процент загрузки */}
      <p style={{
        color: '#666',
        fontSize: 10,
        fontFamily: 'monospace',
      }}>
        {progress}%
      </p>
      
      {/* Стили анимаций */}
      <style>{`
        @keyframes pulseEye {
          0%, 100% { 
            box-shadow: 0 0 0 rgba(255,51,102,0.4);
            transform: scale(1);
          }
          50% { 
            box-shadow: 0 0 20px rgba(255,51,102,0.8);
            transform: scale(1.05);
          }
        }
        
        @keyframes blink {
          0%, 90%, 100% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
          95% { opacity: 0.3; transform: translate(-50%, -50%) scale(0.8); }
        }
        
        @keyframes textGlitch {
          0% { transform: translate(0); opacity: 1; text-shadow: -2px 0 #ff0000, 2px 0 #00ff00; }
          25% { transform: translate(-2px, 1px); text-shadow: 2px 0 #ff0000, -2px 0 #00ff00; }
          50% { transform: translate(2px, -1px); text-shadow: -2px 0 #00ff00, 2px 0 #ff0000; }
          75% { transform: translate(-1px, 2px); text-shadow: 2px 0 #00ff00, -2px 0 #ff0000; }
          100% { transform: translate(0); text-shadow: -2px 0 #ff0000, 2px 0 #00ff00; }
        }
      `}</style>
    </div>
  );
};